clc; clear; close all;

%% ---------------- Robot Parameters (mm) ----------------
L1 = 120;
L2 = 100;

base_height     = 20;
column_height   = 120;
effector_height = 10;

z_home = base_height + column_height - effector_height/2;
z_pick = z_home - 50;   

%% ---------------- Key Cartesian Points ----------------
home   = [150   0   z_home];
object = [120  60   z_home];
target = [180 -60   z_home];

%% ---------------- Motion Helper ----------------
lin = @(p0,p1,n) (p0' + (p1-p0)' .* linspace(0,1,n));

%% ---------------- Trajectory Segments ----------------
T1 = lin(home,   object, 40);                 % move to object
T2 = lin(object, [object(1:2) z_pick], 20);   % lower
T3 = lin([object(1:2) z_pick], object, 20);   % lift
T4 = lin(object, target, 50);                 % move to target
T5 = lin(target, [target(1:2) z_pick], 20);   % lower
T6 = lin([target(1:2) z_pick], target, 20);   % lift
T7 = lin(target, home, 40);                   % return home

trajectory = [T1 T2 T3 T4 T5 T6 T7];

%% ---------------- Figure Setup ----------------
figure('Color','w'); %[output:8db1fdf9]
axis equal; grid on; hold on; %[output:8db1fdf9]
xlabel('X (mm)'); ylabel('Y (mm)'); zlabel('Z (mm)'); %[output:8db1fdf9]
xlim([-250 250]); ylim([-250 250]); zlim([0 200]); %[output:8db1fdf9]

% CHANGE VIEW ANGLE HERE
view(135,30);         %[output:8db1fdf9]
camproj perspective;  %[output:8db1fdf9]

%% ---------------- Object ----------------
obj_pos = object;
picked = false;

%% ---------------- Animation ----------------
for i = 1:size(trajectory,2) %[output:group:8b976ee1]

    x = trajectory(1,i);
    y = trajectory(2,i);
    z = trajectory(3,i);

    %% Inverse Kinematics
    r = sqrt(x^2 + y^2);
    theta2 = acos((r^2 - L1^2 - L2^2)/(2*L1*L2));
    theta1 = atan2(y,x) - atan2(L2*sin(theta2), L1+L2*cos(theta2));
    d3 = base_height + column_height - (z + effector_height/2);

    %% Forward Kinematics
    z0 = base_height + column_height;
    x1 = L1*cos(theta1); y1 = L1*sin(theta1);
    x2 = x1 + L2*cos(theta1+theta2);
    y2 = y1 + L2*sin(theta1+theta2);
    z3 = z0 - d3;

    cla; %[output:7c137b61]

    

% --- BASE PLATE ---
theta = linspace(0,2*pi,40);
r = 30;
fill3(r*cos(theta), r*sin(theta), ... %[output:8db1fdf9] %[output:7c137b61]
      base_height*ones(size(theta)), ... %[output:8db1fdf9] %[output:7c137b61]
      [0.3 0.3 0.3],'FaceAlpha',0.6); %[output:8db1fdf9] %[output:7c137b61]
hold on;

% --- BASE COLUMN ---
plot3([0 0],[0 0], ...
      [base_height base_height+column_height], ...
      'b','LineWidth',8);

% --- ARMS ---
plot3([0 x1],[0 y1],[z0 z0],'r','LineWidth',4);
plot3([x1 x2],[y1 y2],[z0 z0],'b','LineWidth',4);
plot3([x2 x2],[y2 y2],[z0 z3],'g','LineWidth',4);

% --- JOINTS ---
plot3(0,0,z0,'ko','MarkerFaceColor','k');
plot3(x1,y1,z0,'ko','MarkerFaceColor','k');
plot3(x2,y2,z0,'ko','MarkerFaceColor','k');
plot3(x2,y2,z3,'ks','MarkerFaceColor','m','MarkerSize',8);


    %% Pick logic
    if norm([x y z] - [object(1) object(2) z_pick]) < 2
        picked = true;
    end

    %% Place logic
    if norm([x y z] - [target(1) target(2) z_pick]) < 2
        picked = false;
        obj_pos = target;
    end

    %% Update object
    if picked
        obj_pos = [x y z3];
    end

    plot3(obj_pos(1),obj_pos(2),obj_pos(3), ...
        'rs','MarkerSize',10,'MarkerFaceColor','r');

    title('3-DOF SCARA Pick-and-Place Animation');

    

    pause(0.08);
end %[output:group:8b976ee1]


